</style>
</head>
<body>
<div id="div">
  <div id="inner"></div>
</div>
<script>
let scrollendFired = false;
window.addEventListener('scrollend', () => {
  console.log('Window scrollend fired!');
  scrollendFired = true;
});

div.addEventListener('scrollend', () => {
  console.log('Div scrollend fired!');
});

// Test scrolling
window.scrollTo(100, 100);
setTimeout(() => {
  console.log('Scrollend fired:', scrollendFired);
}, 500);
</script>
</body>
</html>
EOF
