/// Schedule a scrollend event for a target that just had a scroll event
fn schedule_scrollend_for_target(&self, target: &EventTarget) {
    // Check if this target is already in the pending scrollend list
    let mut scrollend_targets = self.pending_scrollend_targets.borrow_mut();
    if scrollend_targets.iter().any(|other_target| *other_target == target) {
        return;
    }

    // Get the current scroll position and store it for later comparison
    let (x, y) = self.get_scroll_position(target);
    let target_id = self.get_target_id(target);
    self.scroll_target_positions
        .borrow_mut()
        .insert(target_id, (x, y));

    // Add to pending scrollend targets
    scrollend_targets.push(Dom::from_ref(target));
}

/// Get the current scroll position for a target (document/window or element)
fn get_scroll_position(&self, target: &EventTarget) -> (i32, i32) {
    if let Some(_doc) = target.downcast::<Document>() {
        // This is the window/document
        let window = self.window();
        (window.ScrollX(), window.ScrollY())
    } else if let Some(element) = target.downcast::<Element>() {
        // This is an element
        (element.ScrollLeft() as i32, element.ScrollTop() as i32)
    } else {
        (0, 0)
    }
}

/// Get a unique identifier for a target for position tracking
fn get_target_id(&self, target: &EventTarget) -> u64 {
    if target.downcast::<Document>().is_some() {
        // Use a special ID for the document
        u64::MAX
    } else if let Some(element) = target.downcast::<Element>() {
        // Use the element's node pointer address as ID
        element as *const Element as u64
    } else {
        0
    }
}

/// Fire pending scrollend events for targets where scrolling has completed
pub(crate) fn fire_pending_scrollend_events(&self, can_gc: CanGc) {
    let scrollend_targets = self.pending_scrollend_targets.take();
    for target in scrollend_targets.iter() {
        // Check if the scroll position has changed since we scheduled the scrollend
        let target_id = self.get_target_id(target);
        let (current_x, current_y) = self.get_scroll_position(target);
        let (last_x, last_y) = self
            .scroll_target_positions
            .borrow_mut()
            .remove(&target_id)
            .unwrap_or((current_x, current_y));

        // Only fire scrollend if the position changed
        if current_x != last_x || current_y != last_y {
            if target.downcast::<Document>().is_some() {
                // For document, fire a bubbling event
                target.fire_bubbling_event(Atom::from("scrollend"), can_gc);
            } else if target.downcast::<Element>().is_some() {
                // For element, fire a non-bubbling event
                target.fire_event(Atom::from("scrollend"), can_gc);
            }
        }
    }
}

